.crest img{max-height:48px;max-width:240px;object-fit:contain;display:block}
.title-pre{font-family:var(--f-head);font-size:11px;color:var(--gold);letter-spacing:3px;text-transform:uppercase;margin-bottom:4px}
.name{font-family:var(--f-disp);font-size:23px;font-weight:900;color:var(--t1);letter-spacing:1px;line-height:1.1}
.name-rule{width:64px;height:0;border-top:1px solid var(--gold-line);margin:11px auto 12px;position:relative}
.name-rule::before{content:'◆';position:absolute;top:-8px;left:50%;transform:translateX(-50%);color:var(--gold);font-size:8px;background:var(--card);padding:0 6px}
.tags{display:flex;flex-wrap:wrap;gap:6px;justify-content:center}
.tag{font-family:var(--f-head);font-size:9px;color:var(--t2);border:1px solid var(--bd2);padding:3px 9px;letter-spacing:1px;text-transform:uppercase}
.tag.hi{color:var(--gold);border-color:var(--gold-dim);background:var(--gold-bg)}
.body{padding:18px 22px;position:relative;z-index:2}
.sec{margin-bottom:20px}
.stitle{font-family:var(--f-head);font-size:11px;font-weight:600;color:var(--gold);letter-spacing:2px;text-transform:uppercase;margin-bottom:12px;padding-bottom:7px;border-bottom:1px solid var(--bd);display:flex;align-items:center;gap:9px}
.stitle::before{content:'';width:6px;height:6px;background:var(--gold);transform:rotate(45deg);flex-shrink:0}
.stitle::after{content:'';flex:1;height:1px;background:var(--gold-line)}
.kv-grid{display:flex;flex-direction:column;gap:10px}
.kv{display:grid;grid-template-columns:132px 1fr;gap:12px;align-items:start}
.kv-k{font-family:var(--f-head);font-size:10px;color:var(--t3);letter-spacing:1px;text-transform:uppercase;padding-top:2px}
.kv-v{font-family:var(--f-type);font-size:13px;color:var(--t1);line-height:1.55}
.empty{font-family:var(--f-type);font-style:italic;font-size:12px;color:var(--t3)}
.dual-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}
.dual{background:var(--sec);border:1px solid var(--bd);padding:12px;position:relative}
.dual::before{content:'';position:absolute;left:0;top:0;bottom:0;width:2px;background:var(--gold-dim)}
.dual-k{font-family:var(--f-head);font-size:9px;color:var(--gold);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:6px}
.dual-v{font-family:var(--f-type);font-size:12px;color:var(--t1);line-height:1.55}
.st-grid{display:grid;grid-template-columns:1fr 1fr;gap:11px 18px}
.st{display:flex;flex-direction:column;gap:4px}
.st-top{display:flex;justify-content:space-between;align-items:baseline}
.st-n{font-family:var(--f-head);font-size:10px;color:var(--t2);letter-spacing:0.5px}
.st-v{font-family:var(--f-head);font-size:13px;color:var(--gold);font-weight:700}
.st-bar{height:6px;background:var(--bg);border:1px solid var(--bd2);overflow:hidden}
.st-fill{height:100%;background:var(--gold-dim)}
.st-fill.crit{background:linear-gradient(90deg,var(--gold),var(--gold-hi))}
.lst-wrap{display:flex;flex-direction:column;gap:9px}
.litem{background:var(--sec);border:1px solid var(--bd);border-left:2px solid var(--gold);padding:10px 12px}
.litem-top{display:flex;justify-content:space-between;align-items:baseline;gap:8px;margin-bottom:3px}
.litem-n{font-family:var(--f-head);font-size:13px;font-weight:600;color:var(--t1);letter-spacing:0.4px}
.litem-t{font-family:var(--f-head);font-size:9px;color:var(--gold);letter-spacing:1px;text-transform:uppercase;white-space:nowrap}
.litem-d{font-family:var(--f-type);font-size:12px;color:var(--t2);line-height:1.5}
.txt-blk{font-family:var(--f-type);font-size:13px;color:var(--t1);line-height:1.65;font-style:italic;background:var(--sec);border:1px solid var(--bd);padding:13px 15px;position:relative}
.txt-blk::before{content:'';position:absolute;left:0;top:0;bottom:0;width:2px;background:var(--gold-dim)}
.foot{padding:14px 22px 18px;background:var(--sec);border-top:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center;position:relative;z-index:2}
.foot-side{display:flex;flex-direction:column;gap:2px}
.foot-side .lbl{font-family:var(--f-head);font-size:8px;color:var(--t3);letter-spacing:2px;text-transform:uppercase}
.foot-side .val{font-family:var(--f-head);font-size:11px;color:var(--gold);letter-spacing:1px}
.seal{width:62px;height:62px;border:1px solid var(--gold);display:flex;flex-direction:column;align-items:center;justify-content:center;color:var(--gold);font-family:var(--f-head);text-align:center;background:var(--gold-bg);position:relative}
.seal::before,.seal::after{content:'';position:absolute;width:7px;height:7px;border:1px solid var(--gold)}
.seal::before{top:3px;left:3px;border-right:none;border-bottom:none}
.seal::after{bottom:3px;right:3px;border-left:none;border-top:none}
.seal span{font-size:8px;letter-spacing:1px;line-height:1.3}
.seal .inner{font-family:var(--f-disp);font-size:12px;font-weight:700}
</style>
</head>
<body>
