    <div class="sec"><div class="stitle" id="tSt">Aptitude</div><div id="bSt" class="st-grid"></div></div>
    <div class="sec"><div class="stitle" id="tMr">Mastery &amp; Rank</div><div class="kv-grid" id="bMr"></div></div>
