  </div>
  <div class="foot">
    <div class="foot-side"><span class="lbl" id="footL1">Adventurer’s Guild Archive</span><span class="val" id="footL2">REGISTERED</span></div>
    <div class="seal"><span id="sealT">Soul</span><span class="inner" id="sealM">Reborn</span><span id="sealB">Record</span></div>
  </div>
</div>
<script>
(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?MT_CONFIRM>/gi,'').trim();
  var D={}; try{ if(raw && raw.charAt(0)==='{') D=JSON.parse(raw); }catch(e){}
  if(D.ui_theme==='light') g('card').classList.add('lt');
  var th=(D.ui_lang==='th');
  function tr(map,v){ if(!v) return ''; var o=map[v]; return o?(th?o[1]:o[0]):v; }

  var GEN={male:['Male','ชาย'],female:['Female','หญิง'],other:['Other','อื่นๆ']};
  var RACE={human:['Human','มนุษย์'],migurd:['Migurd','มิเกิร์ด'],superd:['Superd','ซูเปอร์ด'],beast:['Beast Race','เผ่าสัตว์'],elf:['Elf','เอลฟ์'],dwarf:['Dwarf','คนแคระ'],hobbit:['Hobbit','ฮอบบิท'],immortal_demon:['Immortal Demon','ปีศาจอมตะ'],dragonkin:['Dragon-blooded','สายเลือดมังกร'],demon_other:['Demon','ปีศาจ'],mixed:['Mixed-blood','เลือดผสม']};
  var ORI={native:['Native-born of this world','ชาวพื้นเมืองของโลกนี้'],reincarnated:['Reincarnated from another world','กลับชาติมาเกิดจากต่างโลก'],summoned:['Summoned otherworlder','ผู้ถูกอัญเชิญจากต่างโลก'],unknown:['Unknown','ไม่ทราบ']};
  var BIRTH={buena:['Buena Village (Fittoa)','หมู่บ้านบูเอนา (ฟิตโตอา)'],fittoa:['Fittoa Region','เขตฟิตโตอา'],roa:['City of Roa','เมืองโรอา'],asura_capital:['Asuran Royal Capital','เมืองหลวงอาสุระ'],sharia:['Magic City of Sharia','นครเวทมนตร์ชาเรีย'],ranoa:['Ranoa Kingdom','อาณาจักรรานัว'],shirone:['Shirone Kingdom','อาณาจักรชิโรเน'],holy_sword:['Holy Land of the Sword','ดินแดนศักดิ์สิทธิ์แห่งดาบ'],biheiril:['Biheiril Kingdom','อาณาจักรบิเฮริล'],millishion:['Millishion','มิลลิชิออน'],westport:['Westport','เวสต์พอร์ต'],great_forest:['The Great Forest','ป่าใหญ่'],doldia:['Doldia Village','หมู่บ้านโดลเดีย'],migurd_village:['Migurd Village','หมู่บ้านมิเกิร์ด'],rikarisu:['Rikarisu Town','เมืองริคาริสุ'],wind_port:['Wind Port','ท่าเรือลม'],begaritt:['Begaritt Continent','ทวีปเบกาลิต'],sky:['Sky Castle','ปราสาทลอยฟ้า'],earth:['Another world (Earth)','โลกอื่น (โลกมนุษย์)']};
  var HERIT={greyrat:['House Greyrat','ตระกูลเกรย์แรต'],boreas:['Boreas Greyrat','บอเรียส เกรย์แรต'],notos:['Notos Greyrat','โนทอส เกรย์แรต'],asura_noble:['Asuran Nobility','ขุนนางอาสุระ'],millis_noble:['Millis Nobility','ขุนนางมิลลิส'],royalty:['Royalty','เชื้อพระวงศ์'],laplace_factor:['Laplace Factor','ปัจจัยลาปลาส'],migurd_clan:['Migurd Clan','เผ่ามิเกิร์ด'],superd_clan:['Superd Clan','เผ่าซูเปอร์ด'],beast_clan:['Beast Clan','เผ่าสัตว์'],merchant_family:['Merchant Family','ตระกูลพ่อค้า'],orphan:['Orphan','เด็กกำพร้า'],slave:['Former slave','อดีตทาส']};
  var SWSTYLE={none:['None','ไม่มี'],sword_god:['Sword God Style','สำนักเทพดาบ'],water_god:['Water God Style','สำนักเทพน้ำ'],north_god:['North God Style','สำนักเทพเหนือ'],self_taught:['Self-taught','ฝึกด้วยตนเอง']};
  var EYE={none:['None','ไม่มี'],foresight:['Eye of Foresight','ดวงตาแห่งการหยั่งรู้'],farsight:['Eye of Far-Sight','ดวงตาทิพย์'],identification:['Eye of Identification','ดวงตาประเมินค่า'],mana_perception:['Eye of Mana Perception','ดวงตารับรู้มานา'],death:['Eye of Death','ดวงตามรณะ']};
  var SCH={water:['Water Magic','เวทน้ำ'],fire:['Fire Magic','เวทไฟ'],wind:['Wind Magic','เวทลม'],earth:['Earth Magic','เวทดิน'],healing:['Healing Magic','เวทรักษา'],detox:['Detoxification Magic','เวทถอนพิษ'],summoning:['Summoning Magic','เวทอัญเชิญ'],cursed:['Cursed Magic','เวทคำสาป'],formless:['Formless Magic','เวทไร้รูป']};
  var SKL={swordsmanship:['Swordsmanship','การใช้ดาบ'],staff:['Staff / Wand Use','การใช้ไม้เท้า'],archery:['Archery','การยิงธนู'],hand_combat:['Hand-to-Hand','การต่อสู้มือเปล่า'],mana_control:['Mana Control','การควบคุมมานา'],silent_cast:['Silent Casting','การร่ายเงียบ'],enchanting:['Enchanting / Artifacts','การลงอาคม'],crafting:['Crafting / Figurines','งานประดิษฐ์'],alchemy:['Alchemy','การเล่นแร่แปรธาตุ'],beast_taming:['Beast Taming','การฝึกสัตว์'],stealth:['Stealth','การลอบเร้น'],detection:['Detection / Tracking','การตรวจจับ'],cooking:['Cooking / Foraging','การทำอาหาร'],survival:['Wilderness Survival','การเอาตัวรอดในป่า'],medicine:['Medicine','การแพทย์'],linguistics:['Linguistics','ภาษาศาสตร์'],negotiation:['Negotiation','การเจรจา'],leadership:['Leadership','ภาวะผู้นำ'],scholarship:['Scholarship','การค้นคว้า'],teleport_magic:['Teleportation Magic','เวทเทเลพอร์ต']};
  var FAC={guild:['Adventurer’s Guild','สมาคมนักผจญภัย'],house_greyrat:['House Greyrat','ตระกูลเกรย์แรต'],asura_nobility:['Asuran Nobility','ขุนนางอาสุระ'],millis_church:['The Millis Church','โบสถ์มิลลิส'],ranoa_university:['Ranoa University of Magic','มหาวิทยาลัยเวทมนตร์รานัว'],orsted:['Orsted’s Faction','ฝ่ายของออร์สเตด'],hitogami:['Hitogami’s Apostle','สาวกของฮิโตกามิ'],beast_clan:['A Beast Race Clan','เผ่าสัตว์เผ่าหนึ่ง'],demon_court:['A Demon King’s Court','ราชสำนักราชาปีศาจ'],mercenary:['Mercenary Band','กองทหารรับจ้าง'],merchant_guild:['Merchant Guild','สมาคมพ่อค้า']};
  var REP={unknown:['Unknown to the world','ไม่มีใครรู้จัก'],local:['Locally known','เป็นที่รู้จักในท้องถิ่น'],guild_known:['Guild-recognised','เป็นที่ยอมรับในกิลด์'],famous:['Famous','มีชื่อเสียง'],renowned:['Renowned','เลื่องลือ'],notorious:['Notorious','ฉาวโฉ่'],legendary:['Legendary','ระดับตำนาน']};
  var HITO={none:['Never contacted','ไม่เคยติดต่อ'],dreams:['Receives his dreams','ได้รับนิมิตจากเขา'],trusts:['Trusts his guidance','เชื่อคำชี้นำของเขา'],opposes:['Opposes him','ต่อต้านเขา']};
  var RELT={father_mother:['Father / Mother','พ่อ / แม่'],sibling:['Brother / Sister','พี่ / น้อง'],child:['Son / Daughter','ลูก'],spouse:['Spouse','คู่สมรส'],lover:['Lover','คนรัก'],family:['Family','ครอบครัว'],mentor:['Mentor','อาจารย์'],pupil:['Pupil','ศิษย์'],comrade:['Comrade','สหายร่วมรบ'],friend:['Friend','เพื่อน'],rival:['Rival','คู่แข่ง'],nemesis:['Nemesis','ศัตรูคู่อาฆาต'],ally:['Sworn Ally','พันธมิตร'],master:['Master','นาย'],servant:['Servant','คนรับใช้'],stranger:['Stranger of Interest','คนแปลกหน้า']};
  var SCN={childhood_buena:['Childhood in Buena Village','วัยเด็กในหมู่บ้านบูเอนา'],tutor_roa:['Tutoring at the Roa mansion','การเป็นครูที่คฤหาสน์โรอา'],teleport_incident:['The Teleport Incident strikes','ชั่วขณะที่เหตุการณ์วาร์ปเกิดขึ้น'],demon_continent:['Stranded on the Demon Continent','ติดอยู่บนทวีปปีศาจ'],guild_rikarisu:['A job at the Rikarisu guild','งานที่กิลด์ริคาริสุ'],millis_journey:['The road across Millis','การเดินทางข้ามมิลลิส'],sharia_arrival:['Arrival in the Magic City of Sharia','การมาถึงนครเวทมนตร์ชาเรีย'],university_life:['A day at Ranoa University','วันหนึ่งที่มหาวิทยาลัยรานัว'],labyrinth_begaritt:['Descending a Begaritt labyrinth','การดิ่งลงเขาวงกตเบกาลิต'],adventurer_start:['First day as an adventurer','วันแรกในฐานะนักผจญภัย']};

  var STATS=[['mana','Mana Capacity','พลังเวท'],['atk','Attack Magic','เวทโจมตี'],['sup','Support Magic','เวทสนับสนุน'],['sword','Swordsmanship','วิชาดาบ'],['body','Body','ร่างกาย'],['agi','Agility','ความว่องไว'],['int','Intellect','สติปัญญา'],['cha','Charisma','เสน่ห์']];

  if(D.title){ g('pTitle').textContent=D.title; } else { g('pTitle').style.display='none'; }
  g('pName').textContent=(D.name||(th?'ไม่ระบุชื่อ':'Unknown')).toUpperCase();
  g('caseNo').textContent='№ KD-'+(D.year||'417');
  g('stampTxt').textContent=th?'ผนึกแล้ว':'SEALED';
  g('footL1').textContent=th?'หอทะเบียนสมาคมนักผจญภัย':'Adventurer’s Guild Archive';
  g('footL2').textContent=th?'ลงทะเบียนแล้ว':'REGISTERED';
  g('sealT').textContent=th?'วิญญาณ':'Soul';
  g('sealM').textContent=th?'เกิดใหม่':'Reborn';
  g('sealB').textContent=th?'บันทึก':'Record';

  var tags=g('pTags');
  function tag(txt,hi){ if(!txt) return; var d=document.createElement('div'); d.className='tag'+(hi?' hi':''); d.textContent=txt; tags.appendChild(d); }
  tag(D.age?(D.age+(th?' ปี':' yrs')):'', false);
  tag(tr(GEN,D.gender), false);
  tag(tr(RACE,D.race), true);
  tag(tr(FAC,D.faction), false);

  function kv(wrap,k,v){ if(!v) return; var c=document.createElement('div'); c.className='kv';
