  function fillEmpty(w){ if(!w.innerHTML) w.innerHTML='<div class="empty">'+(th?'ไม่ระบุ':'Not recorded')+'</div>'; }

  g('tId').textContent=th?'ตัวตน':'Identity';
  g('tOri').textContent=th?'กำเนิดและสายเลือด':'Origin & Blood';
  g('tSt').textContent=th?'ศักยภาพ':'Aptitude';
  g('tMr').textContent=th?'ความเชี่ยวชาญและระดับ':'Mastery & Rank';
  g('tMag').textContent=th?'สายเวทมนตร์':'Magic Affinities';
  g('tSkl').textContent=th?'ทักษะและความเชี่ยวชาญ':'Skills & Specialties';
  g('tPath').textContent=th?'เส้นทางและฐานะ':'Path & Standing';
  g('tMask').textContent=th?'ภาพลักษณ์และความจริงที่ซ่อนไว้':'Public Face & Private Truth';
