  g('tScn').textContent=th?'ฉากเปิด':'Opening Scene';

  var wId=g('bId');
  kv(wId, th?'ที่มาของวิญญาณ':'Soul Origin', tr(ORI,D.soul_origin));
  kv(wId, th?'รูปลักษณ์':'Appearance', D.appearance);
