  fillEmpty(wId);

  var wOri=g('bOri');
  kv(wOri, th?'เผ่าพันธุ์':'Race', tr(RACE,D.race));
  kv(wOri, th?'ถิ่นกำเนิด':'Birthplace', tr(BIRTH,D.birthplace));
  kv(wOri, th?'มรดก / สายเลือด':'Heritage', tr(HERIT,D.heritage));
  kv(wOri, th?'การเลี้ยงดู':'Upbringing', D.upbringing);
  fillEmpty(wOri);

  var sB=g('bSt'); var stv=D.stats||{};
  STATS.forEach(function(s){ var val=parseInt(stv[s[0]],10); if(isNaN(val)) val=5;
    var w=document.createElement('div'); w.className='st';
    var top=document.createElement('div'); top.className='st-top';
    var n=document.createElement('div'); n.className='st-n'; n.textContent=th?s[2]:s[1];
    var v=document.createElement('div'); v.className='st-v'; v.textContent=val;
    top.appendChild(n); top.appendChild(v);
    var bar=document.createElement('div'); bar.className='st-bar';
    var fl=document.createElement('div'); fl.className='st-fill'+(val>=9?' crit':''); fl.style.width=(val*10)+'%';
    bar.appendChild(fl); w.appendChild(top); w.appendChild(bar); sB.appendChild(w);
