  var L={menu:['Menu','เมนู'],total:['Total','รวม'],order:['Place Order','สั่งซื้อ'],ordered:['ORDERED','สั่งแล้ว'],pick:['Select what you would like','เลือกสิ่งที่ต้องการ'],none:['Nothing on the menu.','ไม่มีรายการ']};
  g('mnShop').textContent=D.shop||D.name||L.menu[th?1:0]; g('mnSub').textContent=D.subtitle||D.sub||'';
  g('mnTotLab').textContent=L.total[th?1:0]; g('mnOrderT').textContent=L.order[th?1:0]; g('mnDoneT').textContent=L.ordered[th?1:0];
  var items=Array.isArray(D.items)?D.items.slice(0,10):[]; var qty=[];
  function coin(c){return COL[c]?c:'copper';}
