    });
    g('mnList').innerHTML=h;
  }
  function recompute(){
    var tot={},any=false;
    items.forEach(function(it,i){ if(qty[i]>0){ any=true; var c=coin(it.coin); tot[c]=(tot[c]||0)+num(it.price)*qty[i]; } });
    if(!any){ g('mnTot').innerHTML='<span class="tempty">'+L.pick[th?1:0]+'</span>'; g('mnOrder').disabled=true; }
