:root{--love:#d96a8f;--inf:#c79a4e;--cheat:#c45a4f;--corr:#9a6cc4;--heat:#e08a4a}
html.lt{--love:#bd476e;--inf:#a8842f;--cheat:#b03a30;--corr:#7a4ca8;--heat:#bd6a23}
.im-sh{display:flex;align-items:center;gap:7px;font-family:var(--fh);font-size:9px;color:var(--gold);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:11px}
.im-sh svg{width:13px;height:13px;stroke:currentColor;fill:none;stroke-width:1.6}
.im-sh::after{content:'';flex:1;height:1px;background:var(--gold-line)}
.im-sh.bonds{margin-top:18px}
.im-you{border:1px solid var(--bd);background:var(--sec);border-left:2px solid var(--gold);padding:12px 13px}
.im-you-nm{font-family:var(--fh);font-size:14px;font-weight:600;color:var(--t1);margin-bottom:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.im-met{margin-bottom:9px}.im-met:last-child{margin-bottom:0}
.im-mt{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}
.im-ml{display:flex;align-items:center;gap:6px;font-family:var(--fh);font-size:9.5px;letter-spacing:1px;text-transform:uppercase;color:var(--t2)}
.im-ml svg{width:12px;height:12px;stroke:currentColor;fill:none;stroke-width:1.8}
.im-mv{font-family:var(--fh);font-size:11px;font-weight:700;color:var(--t1);font-variant-numeric:tabular-nums}
.im-mv .wd{font-family:var(--ft);font-size:9px;font-style:italic;font-weight:400;color:var(--t3);margin-left:5px;text-transform:none;letter-spacing:0}
.im-bar{height:9px;background:var(--bg);border:1px solid var(--bd2);overflow:hidden}
.im-fill{height:100%;transition:width 0.4s}
.im-kk{margin-top:11px}
.im-kl{font-family:var(--fh);font-size:8px;letter-spacing:1.5px;text-transform:uppercase;color:var(--t3);margin-bottom:6px;display:flex;align-items:center;gap:5px}
.im-kl svg{width:11px;height:11px;stroke:currentColor;fill:none;stroke-width:1.8}
.im-chips{display:flex;flex-wrap:wrap;gap:4px}
.im-chip{font-family:var(--ft);font-size:11px;color:var(--gold);border:1px solid var(--gold-dim);background:var(--gold-bg);padding:2px 8px}
.im-none{font-family:var(--ft);font-style:italic;font-size:11px;color:var(--t3)}
.im-pc{border:1px solid var(--bd);background:var(--sec);border-left:2px solid var(--love);padding:12px 13px;margin-bottom:11px}
.im-pc:last-child{margin-bottom:0}
.im-pt{display:flex;align-items:center;gap:9px;margin-bottom:12px}
.im-av{width:30px;height:30px;flex-shrink:0;border:1px solid var(--bd2);background:var(--card);display:flex;align-items:center;justify-content:center;color:var(--love)}
.im-av svg{width:15px;height:15px;stroke:currentColor;fill:none;stroke-width:1.6}
.im-pn{font-family:var(--fh);font-size:14px;font-weight:600;color:var(--t1);line-height:1.2;flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.im-rel{font-family:var(--fh);font-size:8.5px;letter-spacing:1.5px;text-transform:uppercase;color:var(--love);border:1px solid var(--love);background:rgba(217,106,143,0.10);padding:2px 7px;white-space:nowrap;flex-shrink:0}
</style>
</head>
<body>
<textarea id="raw" style="display:none;position:absolute;left:-9999px;">$1</textarea>
<div class="wrap" id="wrap">
  <div class="bar" id="bar">
    <span class="crest"><svg viewBox="0 0 24 24"><path d="M12 2l8 4v6c0 5-3.5 8.5-8 10-4.5-1.5-8-5-8-10V6z"/><path d="M9 12l2 2 4-4"/></svg></span>
    <span class="bar-id"><span class="ttl" id="ttl">STATUS</span><span class="nm" id="nm"></span></span>
    <span class="purse" id="purse"></span>
    <span class="chev"><svg viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg></span>
  </div>
  <div class="body" id="body">
    <div class="seg">
      <div class="tab on" data-p="pProf"><svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/></svg><span id="lP">Profile</span></div>
      <div class="tab" data-p="pAttr"><svg viewBox="0 0 24 24"><line x1="4" y1="21" x2="4" y2="13"/><line x1="4" y1="9" x2="4" y2="3"/><line x1="12" y1="21" x2="12" y2="12"/><line x1="12" y1="8" x2="12" y2="3"/><line x1="20" y1="21" x2="20" y2="15"/><line x1="20" y1="11" x2="20" y2="3"/><line x1="1" y1="13" x2="7" y2="13"/><line x1="9" y1="8" x2="15" y2="8"/><line x1="17" y1="15" x2="23" y2="15"/></svg><span id="lA">Attributes</span></div>
      <div class="tab" data-p="pVit"><svg viewBox="0 0 24 24"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg><span id="lV">Vitals</span></div>
      <div class="tab" data-p="pQuest"><svg viewBox="0 0 24 24"><path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/><path d="M9 13l2 2 4-4"/></svg><span id="lQ">Quests</span></div><div class="tab" id="tInt" data-p="pInt"><svg viewBox="0 0 24 24"><path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/></svg><span id="lI">Intimacy</span></div>
    </div>
    <div class="pane on" id="pProf"></div>
    <div class="pane" id="pAttr"></div>
    <div class="pane" id="pVit"></div>
    <div class="pane" id="pQuest"></div>
    <div class="pane" id="pInt"></div>
  </div>
</div>
<script>
(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?MT_STATUS>/gi,'').trim();
  var D={}; try{ if(raw && raw.charAt(0)==='{') D=JSON.parse(raw);}catch(e){}
  var th=(D.ui_lang==='th');
  if(D.ui_theme==='light') document.documentElement.classList.add('lt');

  function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
  function val(v){ if(v==null) return ''; if(Array.isArray(v)) return v.filter(function(x){return x!=null&&String(x).trim()!=='';}); return String(v).trim(); }
  function num(v){ var n=parseInt(v,10); return isNaN(n)?0:n; }
  function fmt(n){ return String(n).replace(/\B(?=(\d{3})+(?!\d))/g,','); }

  g('ttl').textContent= th?'สถานะ':'STATUS';
  g('nm').textContent= val(D.name)|| (th?'ไม่ระบุชื่อ':'Unknown');
  g('lP').textContent= th?'โปรไฟล์':'Profile';
  g('lA').textContent= th?'ความสามารถ':'Attributes';
  g('lV').textContent= th?'ร่างกาย':'Vitals';
  g('lQ').textContent= th?'ภารกิจ':'Quests';
  g('lI').textContent= th?'ความสัมพันธ์':'Intimacy';

  /* ---- currency data ---- */
  var CUR=[['green','Green Ore','แร่เขียว','#4fa86b'],['gold','Gold','ทอง','#d8b13f'],['silver','Silver','เงิน','#c2c8d0'],['copper','Copper','ทองแดง','#c2783f'],['iron','Iron','เหล็ก','#8a8f98'],['stone','Stone','หิน','#9a8f7a']];
  var cur=D.currency||{};
  var owned=CUR.filter(function(c){ return cur[c[0]]!=null && String(cur[c[0]]).trim()!=='' && num(cur[c[0]])>0; });

  /* bar purse (top 4 highest-value present) */
  var ph='';
  owned.slice(0,4).forEach(function(c){ ph+='<span class="ppill"><span class="cdot" style="background:'+c[3]+'"></span>'+fmt(num(cur[c[0]]))+'</span>'; });
  g('purse').innerHTML=ph;

  /* ---- profile ---- */
  var IC={
    name:'<circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/>',
    age:'<circle cx="12" cy="12" r="9"/><polyline points="12 7 12 12 16 14"/>',
    gender:'<circle cx="12" cy="10" r="5"/><line x1="12" y1="15" x2="12" y2="22"/><line x1="9" y1="19" x2="15" y2="19"/>',
    family:'<path d="M3 11l9-7 9 7"/><path d="M5 10v10h14V10"/><path d="M10 20v-6h4v6"/>',
    rank:'<polyline points="6 14 12 8 18 14"/><polyline points="6 18 12 12 18 18"/>',
    guild:'<path d="M4 21V4l9 2v13"/><path d="M13 6l7 1.5V17l-7-1.5"/>',
    magic_affinity:'<path d="M12 3l1.8 4.7L18 9l-4.2 1.3L12 15l-1.8-4.7L6 9l4.2-1.3z"/><circle cx="18" cy="18" r="1.5"/><circle cx="5" cy="16" r="1"/>',
    technique:'<path d="M14 3l7 7-9 9-3 1 1-3z"/><line x1="5" y1="19" x2="9" y2="15"/>',
    reputation:'<polygon points="12 3 14.6 8.6 21 9.3 16.5 13.7 17.8 20 12 16.8 6.2 20 7.5 13.7 3 9.3 9.4 8.6"/>',
    occupation:'<rect x="3" y="7" width="18" height="13" rx="1"/><path d="M8 7V5a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>'
  };
  var LB={name:['Name','ชื่อ'],age:['Age','อายุ'],gender:['Gender','เพศ'],family:['Family','ครอบครัว'],rank:['Rank','ยศ'],guild:['Guild / Party','สังกัด / ปาร์ตี้'],magic_affinity:['Magic Affinity','สายเวทมนตร์'],technique:['Technique','วิชา / เทคนิค'],reputation:['Reputation','ชื่อเสียง'],occupation:['Occupation','อาชีพ']};
  var order=['name','age','gender','family','rank','guild','reputation','occupation','magic_affinity','technique'];
  var wide={name:1,family:1,magic_affinity:1,technique:1};

  var pro='';
  /* wallet block first */
  if(owned.length){
    pro+='<div class="wallet"><div class="wallet-h"><svg viewBox="0 0 24 24"><path d="M3 7h15a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><path d="M16 12h3"/><path d="M3 7l13-3 2 3"/></svg>'+(th?'กระเป๋าเงิน':'Wallet')+'</div><div class="coins">';
    owned.forEach(function(c){
      pro+='<div class="coin"><span class="cdot" style="background:'+c[3]+'"></span><span class="coin-i"><span class="coin-n">'+fmt(num(cur[c[0]]))+'</span><span class="coin-l">'+esc(th?c[2]:c[1])+'</span></span></div>';
    });
    pro+='</div>';
    if(val(cur.note)) pro+='<div class="wallet-note">'+esc(cur.note)+'</div>';
    pro+='</div>';
  }
  /* info grid */
  var present=order.filter(function(k){ var v=val(D[k]); return v && !(Array.isArray(v)&&!v.length); });
  var any=present.length>0;
  /* promote the final half-width field to full when the half count is odd, so no orphan gap is left */
  var halves=present.filter(function(k){return !wide[k];});
  var promote=(halves.length%2===1)?halves[halves.length-1]:null;
  var grid='';
  present.forEach(function(k){
    var v=val(D[k]);
    var vh = Array.isArray(v) ? '<div class="chips">'+v.map(function(x){return '<span class="chip">'+esc(x)+'</span>';}).join('')+'</div>' : esc(v);
    var full=wide[k]||k===promote;
    grid+='<div class="info'+(full?' full':'')+'"><span class="info-ic"><svg viewBox="0 0 24 24">'+IC[k]+'</svg></span><span class="info-b"><span class="info-l">'+esc(LB[k][th?1:0])+'</span><span class="info-v">'+vh+'</span></span></div>';
  });
  if(any) pro+='<div class="grid">'+grid+'</div>';
  if(!any && !owned.length) pro='<div class="empty">'+(th?'ยังไม่มีข้อมูล':'No data yet')+'</div>';
  g('pProf').innerHTML=pro;

  /* ---- attributes (1-10 skills that improve during play) ---- */
  var attrs=D.attributes; var aarr=[];
  if(Array.isArray(attrs)) aarr=attrs.map(function(a){return {name:(a.name||a.n||''),lv:num(a.level!=null?a.level:a.lv),desc:(a.desc||a.d||'')};});
  else if(attrs && typeof attrs==='object'){ for(var ak in attrs){ aarr.push({name:ak,lv:num(attrs[ak]),desc:''}); } }
  aarr=aarr.filter(function(a){return a.name;});
  if(aarr.length){
    var ah='';
    aarr.forEach(function(a){
      var lv=Math.max(0,Math.min(10,a.lv)); var segs='';
      for(var i=1;i<=10;i++){ segs+='<div class="at-tk'+(i<=lv?' on':'')+(i>=9&&i<=lv?' hi':'')+'"></div>'; }
      ah+='<div class="at-wrap"><div class="at-top"><span class="at-n">'+esc(a.name)+'</span><span class="at-v">'+lv+'<span class="of">/10</span></span></div>'+(a.desc?'<div class="at-d">'+esc(a.desc)+'</div>':'')+'<div class="at-bar">'+segs+'</div></div>';
    });
    g('pAttr').innerHTML=ah;
  } else {
    g('pAttr').innerHTML='<div class="empty">'+(th?'ยังไม่มีความสามารถบันทึกไว้':'No attributes tracked yet')+'</div>';
  }

  /* ---- vitals ---- */
  function bar(obj,cls,label,icon,note){
    if(!obj) return '';
    var cur2=num(obj.cur), max=num(obj.max)||100; var pct=max>0?Math.max(0,Math.min(100,Math.round(cur2/max*100))):0; var dep=cur2<=0;
    var h='<div class="vit"><div class="vtop"><div class="vn">'+icon+esc(label)+'</div><div class="vv">'+fmt(cur2)+' / '+fmt(max)+'<span class="vpct">'+pct+'%</span></div></div>';
    h+='<div class="vbar"><div class="vfill '+cls+(dep?' dep':'')+'" style="width:'+(dep?100:pct)+'%"></div></div>';
    if(dep) h+='<div class="vnote"><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12" y2="16"/></svg>'+esc(note)+'</div>';
    h+='</div>'; return h;
  }
  var staI='<svg viewBox="0 0 24 24"><path d="M13 2L4.5 13.5H11l-1 8.5L19.5 10H13z"/></svg>';
  var manI='<svg viewBox="0 0 24 24"><path d="M12 3C9 8 6 11 6 15a6 6 0 0 0 12 0c0-4-3-7-6-12z"/></svg>';
  var vh='';
  vh+=bar(D.stamina,'sta', th?'พลังกาย (Stamina)':'Stamina', staI, th?'พละกำลังหมด — ใช้วิชา/เทคนิคไม่ได้':'Stamina depleted — techniques sealed');
  vh+=bar(D.mana,'man', th?'พลังเวท (Magic)':'Magic Capacity', manI, th?'พลังเวทหมด — ใช้เวทมนตร์ไม่ได้':'Mana depleted — magic sealed');
  g('pVit').innerHTML= vh||'<div class="empty">'+(th?'ยังไม่มีข้อมูล':'No data yet')+'</div>';

  /* ---- quests ---- */
  var QS={ongoing:['Ongoing','กำลังดำเนินการ'],success:['Success','สำเร็จ'],failed:['Failed','ล้มเหลว']};
  var qarr=Array.isArray(D.quests)?D.quests:(D.quest?[D.quest]:[]);
  if(qarr.length){
    var qh='';
    qarr.forEach(function(qq){
      var stt=(qq.status||'ongoing').toLowerCase(); if(!QS[stt]) stt='ongoing';
      qh+='<div class="q"><div class="qtop"><div class="qn">'+esc(val(qq.name)||(th?'ภารกิจ':'Quest'))+'</div>';
      if(val(qq.rank)) qh+='<div class="qrank">'+esc(qq.rank)+'</div>';
      qh+='<div class="qst '+stt+'">'+esc(QS[stt][th?1:0])+'</div></div>';
      if(val(qq.objective)) qh+='<div class="qobj"><span class="ql">'+(th?'เป้าหมาย':'Objective')+'</span><span>'+esc(qq.objective)+'</span></div>';
      if(val(qq.info)) qh+='<div class="qinfo">'+esc(qq.info)+'</div>';
      qh+='</div>';
    });
    g('pQuest').innerHTML=qh;
  } else {
    g('pQuest').innerHTML='<div class="empty">'+(th?'ไม่มีภารกิจที่กำลังดำเนินการ':'No active quests')+'</div>';
  }


  /* ---- intimacy (kink/fetish + partner meters) ---- */
  (function(){
    var IM=D.intimacy||{}; var U=IM.user||{};
    function cl(v){var n=parseInt(v,10);if(isNaN(n))n=0;return Math.max(0,Math.min(100,n));}
    function ka(v){ if(v==null)return[]; if(Array.isArray(v))return v.filter(function(x){return x!=null&&String(x).trim()!=='';}); return String(v).split(/[,;]+/).map(function(x){return x.trim();}).filter(Boolean); }
    var ps=Array.isArray(IM.partners)?IM.partners.filter(function(p){return p&&(p.name||p.npc);}).slice(0,3):[];
    var ukk=ka(U.kinks!=null?U.kinks:U.fetishes);
    var hasU=(U.heat!=null)||(U.corruption!=null)||ukk.length>0;
    if(!ps.length && !hasU){ var ht=g('tInt'); if(ht)ht.style.display='none'; var hp=g('pInt'); if(hp)hp.style.display='none'; return; }
    var IC={
      love:'<path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/>',
      influence:'<circle cx="12" cy="12" r="3"/><path d="M12 2v3M12 19v3M2 12h3M19 12h3M5 5l2 2M17 17l2 2M19 5l-2 2M7 17l-2 2"/>',
      infidelity:'<path d="M12 21C7 17 3 13 3 8.5A4.5 4.5 0 0 1 12 6a4.5 4.5 0 0 1 9 2.5C21 13 17 17 12 21z"/><line x1="4" y1="3" x2="20" y2="20"/>',
      corruption:'<path d="M12 3l1.8 4.7L18 9l-4.2 1.3L12 15l-1.8-4.7L6 9l4.2-1.3z"/><circle cx="18" cy="18" r="1.5"/><circle cx="5" cy="16" r="1"/>',
      heat:'<path d="M12 3C9 8 6 11 6 15a6 6 0 0 0 12 0c0-4-3-7-6-12z"/>'
    };
    var LB2={love:['Love','ความรัก'],influence:['Influence','อิทธิพล'],infidelity:['Infidelity','นอกใจ'],corruption:['Corruption','ความเสื่อม'],heat:['Heat / Lust','ราคะ']};
    var CO={love:'var(--love)',influence:'var(--inf)',infidelity:'var(--cheat)',corruption:'var(--corr)',heat:'var(--heat)'};
    function word(k,v){ var sc;
      if(k==='love')sc=th?['เย็นชา','ห่างเหิน','อบอุ่น','ผูกพัน','ลุ่มหลง','ภักดี']:['Cold','Distant','Warm','Attached','Smitten','Devoted'];
      else if(k==='influence')sc=th?['ไม่มี','เล็กน้อย','ปานกลาง','สูง','ครอบงำ','สิ้นเชิง']:['None','Slight','Moderate','Strong','Dominant','Total'];
      else if(k==='infidelity')sc=th?['ซื่อสัตย์','มั่นคง','ไขว้เขว','ล่อแหลม','คบซ้อน','นอกใจ']:['Faithful','Steady','Tempted','Risky','Straying','Unfaithful'];
      else if(k==='corruption')sc=th?['บริสุทธิ์','ไร้เดียงสา','สงสัย','ถูกชักจูง','เสื่อมทราม','พังทลาย']:['Pure','Innocent','Curious','Swayed','Corrupted','Broken'];
      else sc=th?['เยือกเย็น','สงบ','อุ่น','เร่าร้อน','ร้อนรุ่ม','คลั่งไคล้']:['Frigid','Calm','Warm','Aroused','Burning','Feral'];
      var i=Math.floor(v/(100/sc.length)); if(v>=100)i=sc.length-1; if(v<=0)i=0; if(i>sc.length-1)i=sc.length-1; return sc[i]; }
    function meter(k,v){ v=cl(v); return '<div class="im-met"><div class="im-mt"><span class="im-ml"><svg viewBox="0 0 24 24">'+IC[k]+'</svg>'+esc(LB2[k][th?1:0])+'</span><span class="im-mv">'+v+'<span class="wd">'+esc(word(k,v))+'</span></span></div><div class="im-bar"><div class="im-fill" style="width:'+v+'%;background:'+CO[k]+'"></div></div></div>'; }
    function kk(label,list){ var items=ka(list); var h='<div class="im-kk"><div class="im-kl"><svg viewBox="0 0 24 24"><path d="M12 2l2.4 7.4H22l-6 4.5 2.3 7.1L12 16.6 5.7 21l2.3-7.1-6-4.5h7.6z"/></svg>'+esc(label)+'</div>'; if(items.length)h+='<div class="im-chips">'+items.map(function(x){return '<span class="im-chip">'+esc(x)+'</span>';}).join('')+'</div>'; else h+='<div class="im-none">'+(th?'ยังไม่เปิดเผย':'None revealed yet')+'</div>'; return h+'</div>'; }
    var html='<div class="im-sh"><svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/></svg>'+(th?'ตัวคุณ':'Yourself')+'</div>';
    html+='<div class="im-you"><div class="im-you-nm">'+esc(val(D.name)||(th?'คุณ':'You'))+'</div>';
    html+=meter('heat',U.heat);
    if(U.corruption!=null)html+=meter('corruption',U.corruption);
